import React, { useState, useEffect } from 'react';
import { API_BASE_URL } from '../config';

const Banner = () => {
    const [banners, setBanners] = useState([]);
    const [index, setIndex] = useState(0);

    useEffect(() => {
        fetch('/data.json')
            .then(res => res.json())
            .then(data => setBanners(data.banners));
    }, []);

    // Auto-slide logic
    useEffect(() => {
        if (banners.length === 0) return;
        const interval = setInterval(() => {
            setIndex((prev) => (prev + 1) % banners.length);
        }, 3000); // 3 second mein slide change hoga
        return () => clearInterval(interval);
    }, [banners]);

    return (
        <div className="relative w-full h-[400px] overflow-hidden">
            {banners.map((item, i) => (
                <div key={item.id} className={`absolute w-full transition-opacity duration-1000 ${i === index ? 'opacity-100' : 'opacity-0'}`}>
                    <img src={item.imageUrl} alt={item.title} className="w-full h-[400px] object-cover" />
                    <h2 className="absolute top-10 left-10 text-white text-4xl font-bold">{item.title}</h2>
                </div>
            ))}
        </div>
    );
};

export default Banner;