import React from 'react';
// Components import
import Hero from '../components/Hero';
import Banner from '../components/Banner';
import About from '../components/About';
import Products from '../components/Products';
import WhyChooseUs from '../components/WhyChooseUs';
import StatsSection from '../components/StatsSection';
import CTASection from '../components/CTASection';
import WelcomeSection from '../components/WelcomeSection';
import ClientSlider from '../components/ClientSlider';
import CertificateSection from '../components/CertificateSection';

// Central config se URL import karein
import { API_BASE_URL } from '../config';

const Home = () => {
    // Note: Humein ab 'isLocal' check karne ki zaroorat nahi hai 
    // kyunki hamara API_BASE_URL har jagah live server par point kar raha hai.

    return (
        <>
            {/* Aap chahein toh condition rakh sakte hain, 
                lekin fetch URL hamesha API_BASE_URL se aayega */}
            <Hero />
            <Banner />
            <About />
            <Products />
            <WhyChooseUs />
            <ClientSlider />
            <WelcomeSection />
            <StatsSection />
            <CTASection />
            <CertificateSection />
        </>
    );
};

export default Home;